import { readFile, writeFile } from "node:fs/promises";
import { createWorkspace } from "@tigrisdata/agent-kit";
import { put } from "@tigrisdata/storage";

async function main() {
  try {
    const trialId = (await readFile("/logs/artifacts/trial_id", "utf-8")).trim();
    const wsName = `harbor-ws-${trialId}`.toLowerCase().replace(/[^a-z0-9.-]/g, "-");

    const { data: workspace, error: wsError } = await createWorkspace(wsName, {
      ttl: { days: 1 },
      credentials: { role: "Editor" }
    });

    if (wsError) {
      console.error("Error creating workspace:", wsError);
      process.exit(1);
    }
    if (!workspace || !workspace.credentials) {
      console.error("Workspace or credentials missing");
      process.exit(1);
    }

    const scopedKeyId = workspace.credentials.accessKeyId;
    const scopedSecret = workspace.credentials.secretAccessKey;
    const bucket = workspace.bucket;

    const body = `{"status":"ok","run":"${trialId}"}`;

    const { data: putData, error: putError } = await put("state.json", body, {
      contentType: "application/json",
      config: {
        bucket,
        accessKeyId: scopedKeyId,
        secretAccessKey: scopedSecret
      }
    });

    if (putError) {
      console.error("Error putting object:", putError);
      process.exit(1);
    }

    console.log(scopedKeyId);
    await writeFile("/home/user/tigris-task/output.log", scopedKeyId);

  } catch (err) {
    console.error("Unexpected error:", err);
    process.exit(1);
  }
}

main();
